                // exactly as the old ThreadAbortException handler did.
                RollbackCurrentTransaction();
                break; // exit the loop cleanly
            }
            finally
            {
                FlushBuffers();
            }
        }
    }

    public void Stop()
    {
        // Signal cancellation (unblocks any token-aware call immediately).
        _cts.Cancel();

        if (_workerThread is { IsAlive: true })
        {
            // Block until the thread exits or 2 seconds elapse.
            // Unlike Thread.Sleep, Join actually waits for *this* thread.
            if (!_workerThread.Join(TimeSpan.FromSeconds(2)))
