                // safe equivalent of Abort() in .NET 8. If this happens,
                // the blocking call inside GetNextItem is not honoring the
                // CancellationToken and must be fixed.
                Console.Error.WriteLine(
                    "WARNING: Worker thread did not exit within timeout.");
            }
        }
    }

    public void Dispose()
    {
        Stop();
        _cts.Dispose();
    }

    // --- Stubs: adapt these to accept CancellationToken ---

    private object GetNextItem(CancellationToken token)
    {
        // Example: if backed by a BlockingCollection<T>, use:
        //   return _queue.Take(token);
        // The token makes Take() throw OperationCanceledException
        // instead of blocking forever.
        throw new NotImplementedException();
    }

    private void ProcessItem(object item, CancellationToken token)
    {
